UPDATE USER_INFO
SET
     USER_NM  = #{userNm}
    ,CO_ID = #{coId}
    ,DEPT_ID    = #{deptId}
    ,JBPS_NM   = #{jbpsNm}
    ,AUTHRT_ID    = #{authrtId}
    ,USER_TELNO   = #{userTelno}
    ,USE_YN   = #{useYn}
    ,MEMO_CN       = #{memoCn}
    ,USER_ENPSWD = #{userEnpswd}
WHERE USER_ID = #{userId}

choose.otherwise:
SELECT U.USER_ID ,U.USER_NM ,U.CO_ID ,U.DEPT_ID ,D.DEPT_NM ,D.UP_DEPT_ID ,D.SORT_SEQ ,U.JBPS_NM ,U.USER_TELNO FROM USER_INFO U LEFT JOIN DEPT_INFO D ON D.DEPT_ID = U.DEPT_ID WHERE U.USE_YN = 'Y' AND U.CO_ID = #{coId}
AND (U.USER_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR U.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%') OR IFNULL(D.DEPT_NM, '') LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY IFNULL(D.SORT_SEQ, 9999) ASC, U.USER_NM ASC, U.USER_ID ASC

mapper.select:
SELECT U.USER_ID ,U.USER_NM ,U.CO_ID ,C.CO_CD ,C.CO_NM ,U.DEPT_ID ,D.DEPT_NM ,PD.DEPT_NM AS PARENT_DEPT_NM ,U.JBPS_NM ,U.AUTHRT_ID ,A.AUTHRT_NM ,U.USER_TELNO ,U.USE_YN ,U.MEMO_CN ,DATE_FORMAT(U.REG_DT, '%Y-%m-%d') AS REG_DT FROM USER_INFO U LEFT JOIN AUTHRT_INFO A ON U.AUTHRT_ID = A.AUTHRT_ID LEFT JOIN CO_INFO C ON U.CO_ID = C.CO_ID LEFT JOIN DEPT_INFO D ON U.DEPT_ID = D.DEPT_ID LEFT JOIN DEPT_INFO PD ON D.UP_DEPT_ID = PD.DEPT_ID WHERE U.CO_ID = #{coId} AND U.DEPT_ID = #{deptId} AND U.AUTHRT_ID = #{authrtId} AND U.USE_YN = #{useYn}
AND (U.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%') OR U.USER_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR IFNULL(D.DEPT_NM, '') LIKE CONCAT('%', #{searchKeyword}, '%') OR IFNULL(U.JBPS_NM, '') LIKE CONCAT('%', #{searchKeyword}, '%') OR IFNULL(U.USER_TELNO, '') LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY IFNULL(D.SORT_SEQ, 9999) ASC, U.USER_NM ASC, U.USER_ID ASC

